properties.SQL Query:
SELECT Identifier, HealthStatusEUCAIM as assessment_code, ValueAsConceptEUCAIM as assesment_value_as_concept, ValueAsNumber as assesment_value_as_number, ValueAsConceptUnitEUCAIM as assesment_value_as_concept
from eucaim_cdm_ingestion.healthstatus
WHERE processed = FALSE;

SELECT TreatmentIdentifier, MedicationCodeEUCAIM as medication_code, OffsetUnitEUCAIM as medication_offset_unit, OffsetFromDiagnosis as medication_offset_from_diagnosis, DateOfMedication as medication_start_date
from eucaim_cdm_ingestion.cancerrelatedmedication
WHERE processed = FALSE;

SELECT ProcedureIdentifier, ProcedureEUCAIM as procedure_code, PerformedDate as procedure_date, OffsetFromDiagnosis as procedure_offset_from_diagnosis, OffsetUnitEUCAIM as procedure_offset_unit
from eucaim_cdm_ingestion.cancerrelatedprocedure
WHERE processed = FALSE;

SELECT Identifier, TumorMarkerEUCAIM as tumor_marker_test_code, ValueAsNumber as tumor_marker_test_as_number, ValueAsConceptEUCAIM as tumor_marker_test_as_concept, ValueAsConceptUnitEUCAIM as tumor_marker_test_as_unit, DateOfMarker as tumor_marker_date
from eucaim_cdm_ingestion.tumormarkertest
WHERE processed = FALSE;

SELECT TreatmentIdentifier, 'GEN1000018' as treatment_type, RadiotherapyEUCAIM as radiotherapy_modality, PerformedDate as radiotherapy_start_date, OffsetFromDiagnosis as radiotherapy_offset_from_diagnosis, OffsetUnitEUCAIM as radiotherapy_offset_unit
from eucaim_cdm_ingestion.radiotherapycoursesummary
WHERE processed = FALSE;

SELECT Identifier, CodeEUCAIM as lab_test_code, ValueAsConceptEUCAIM as lab_test_value_as_concept, ValueUnitEUCAIM as lab_test_value_unit, ValueAsNumber as lab_test_value_as_number, DateOfTestResult as lab_test_date, OffsetFromDiagnosis as lab_test_offset_from_diagnosis, OffsetUnitEUCAIM as lab_test_offset_unit
from eucaim_cdm_ingestion.labtestresult
WHERE processed = FALSE;

SELECT ProcedureIdentifier, ImagingProcedureEUCAIM as procedure_code, PerformedDate as procedure_date, OffsetFromDiagnosis as procedure_offset_from_diagnosis, OffsetUnitEUCAIM as procedure_offset_unit, PerformedDate as procedure_date, ImagingTimepoint
from eucaim_cdm_ingestion.imagingprocedure
WHERE processed = FALSE;

SELECT Identifier, AssertedDate as cancer_condition_asserted_date, AgeOfDiagnosis as cancer_condition_age_at_diagnosis, AgeUnitEUCAIM as cancer_condition_age_unit, PrimaryCancerConditionEUCAIM as cancer_condition_code, HistologyMorphologyBehaviourEUCAIM as cancer_condition_histology_morphology
from eucaim_cdm_ingestion.PrimaryCancerCondition
WHERE processed = false;

SELECT TreatmentIdentifier, 'GEN1000016' as treatment_type, ProcedureEUCAIM as surgical_procedure_code, PerformedDate as surgical_procedure_date, OffsetFromDiagnosis as surgical_procedure_offset_from_diagnosis, OffsetUnitEUCAIM as surgical_procedure_offset_from_diagnosis_unit
from eucaim_cdm_ingestion.surgicalprocedure
WHERE processed = FALSE;

SELECT Identifier, CancerStageCodeEUCAIM as cancer_stage_code, CancerStageValueEUCAIM as cancer_stage_as_concept
from eucaim_cdm_ingestion.cancerstage
WHERE processed = FALSE;

SELECT Identifier, BodySiteEUCAIM as tumor_body_site, BodySiteLocationQualifierEUCAIM as tumor_body_site_location, BodySiteLateralityQualifierEUCAIM as tumor_body_site_laterality, volume as tumor_volume, sizeDimensionUnit as tumor_size_dimension_unit, sizeMaximumDimension as tumor_size_maximum_dimension, sizeMethodEUCAIM as tumor_size_method, morphologyEUCAIM as tumor_histology_morphology
from eucaim_cdm_ingestion.tumor
WHERE processed = FALSE;

SELECT DatasetIdentifier, PatientIdentifier, TypeEUCAIM as episode_type_code, EpisodeNumber as episode_number, StartDate as episode_start_date
from eucaim_cdm_ingestion.episode
WHERE processed = FALSE;
